const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {

  // ✅ Convert AQI to number safely
  const getAQIColor = (value) => {
    const aqiValue = Number(value);

    const colors = {
      1: "#00e400", // Green
      2: "#ffff00", // Yellow
      3: "#ff7e00", // Orange
      4: "#ff0000", // Red
      5: "#8f3f97", // Purple
      6: "#7e0023"  // Maroon
    };

    return colors[aqiValue] || "#ccc"; // fallback if undefined
  };

  const getAQILabel = (value) => {
    const aqiValue = Number(value);

    const labels = {
      1: "Good",
      2: "Moderate",
      3: "Unhealthy (Sensitive)",
      4: "Unhealthy",
      5: "Very Unhealthy",
      6: "Hazardous"
    };

    return labels[aqiValue] || "Unknown";
  };

  return (
    <div className="card">
      <h2>{city}</h2>

      <img src={icon} alt="weather icon" />

      <p>{temperature}</p>
      <p>{feelsLike}</p>
      <p>{condition}</p>
      <p>{wind}</p>
      <p>{humidity}</p>

      {/* 🔥 AQI BOX */}
      <div
        style={{
          backgroundColor: getAQIColor(aqi),
          padding: "10px",
          borderRadius: "8px",
          marginTop: "10px",
          color: "#000",
          fontWeight: "bold"
        }}
      >
        AQI: {aqi || "N/A"} {aqi ? `— ${getAQILabel(aqi)}` : ""}
      </div>
    </div>
  );
};

export default WeatherCard;
